                "scopri": [
                    {
                        "id": 301,
                        "title": "Cos'\u00e8 l'Ortografia",
                        "theory": "L'<span style=\"color: #27ae60; font-weight: bold;\">ORTOGRAFIA</span> \u00e8 l'insieme delle regole che insegnano a scrivere correttamente le parole di una lingua.<br><br>Le principali insidie grafiche riguardano:<br>\u2022 <b>ce / cie</b> (es. <i>cielo, specie</i>)<br>\u2022 <b>ge / gie</b> (es. <i>igiene, ciliegie</i>)<br>\u2022 <b>cu / qu / cqu</b> (es. <i>cuore, quadro, acqua</i>)<br>\u2022 <b>li / gli</b> (es. <i>milione, maglia</i>)<br>\u2022 <b>gn / gni</b> (es. <i>disegno, sogniamo</i>)<br>\u2022 <b>sce / scie</b> (es. <i>scienza, sceriffo</i>).",
                        "text": "Quale grafia \u00e8 corretta?",
                        "options": [
                            "Scienza",
                            "Scenza"
                        ],
                        "answer": "Scienza"
                    },
                    {
                        "id": 302,
                        "title": "La Sillaba",
                        "theory": "La <span style=\"color: #d35400; font-weight: bold;\">SILLABA</span> \u00e8 un gruppo di lettere pronunciato con un'unica emissione di voce.<br>Ogni sillaba deve contenere almeno una vocale.<br><br>In base al numero di sillabe, le parole si dividono in:<br>\u2022 <b>Monosillabi</b>: una sillaba (es. <i>re, me</i>)<br>\u2022 <b>Bisillabi</b>: due sillabe (es. <i>ca-sa</i>)<br>\u2022 <b>Trisillabi</b>: tre sillabe (es. <i>ta-vo-lo</i>)<br>\u2022 <b>Polisillabi</b>: quattro o pi\u00f9 sillabe (es. <i>te-le-fo-no</i>).",
                        "text": "La parola 'sole' \u00e8 un:",
                        "options": [
                            "Monosillabo",
                            "Bisillabo"
                        ],
                        "answer": "Bisillabo"
                    },
                    {
                        "id": 303,
                        "title": "L'Accento Grafico e Fonico",
                        "theory": "L'<span style=\"color: #2980b9; font-weight: bold;\">ACCENTO</span> \u00e8 la forza con cui si pronuncia una sillaba.<br><br>\u2022 <span style=\"color: #e84393; font-weight: bold;\">ACCENTO FONICO</span>: indica se la vocale \u00e8 aperta (grave: `\u00e8, \u00f2`) o chiusa (acuto: `\u00e9, \u00f3`).<br>\u2022 <span style=\"color: #8e44ad; font-weight: bold;\">ACCENTO GRAFICO</span>: \u00e8 obbligatorio sulle parole tronche (es. <i>caff\u00e8, virt\u00f9</i>) e su alcuni monosillabi (es. <i>l\u00ec, l\u00e0, s\u00ec, d\u00e0, n\u00e9</i>) per non confonderli con omografi.",
                        "text": "La parola 'perch\u00e9' richiede l'accento:",
                        "options": [
                            "Acuto (\u00e9)",
                            "Grave (\u00e8)"
                        ],
                        "answer": "Acuto (\u00e9)"
                    },
                    {
                        "id": 304,
                        "title": "Elisione e Troncamento",
                        "theory": "\u2022 <span style=\"color: #16a085; font-weight: bold;\">ELISIONE</span>: \u00e8 la caduta della vocale finale non accentata davanti a un'altra vocale. Richiede l'apostrofo (es. <i>l'amica, bell'aspetto</i>).<br><br>\u2022 <span style=\"color: #e67e22; font-weight: bold;\">TRONCAMENTO</span>: \u00e8 la caduta della vocale o sillaba finale davanti a parole che iniziano per vocale o consonante. <b>NON</b> vuole l'apostrofo (es. <i>un uomo, tal dei tali, bel tipo</i>).",
                        "text": "Nella frase 'un amico', 'un' \u00e8:",
                        "options": [
                            "Un'elisione",
                            "Un troncamento"
                        ],
                        "answer": "Un troncamento"
                    },
                    {
                        "id": 305,
                        "title": "Punteggiatura e Maiuscole",
                        "theory": "\u2022 La <span style=\"color: #2c3e50; font-weight: bold;\">PUNTEGGIATURA</span> regola il ritmo, le pause e l'espressivit\u00e0 del testo (es. <i>punto, virgola, due punti</i>).<br><br>\u2022 La <span style=\"color: #27ae60; font-weight: bold;\">LETTERA MAIUSCOLA</span> \u00e8 obbligatoria all'inizio di un periodo, dopo il punto (fermo, interrogativo, esclamativo) e per tutti i nomi propri (es. <i>Roma, Mario</i>).",
                        "text": "La lettera maiuscola \u00e8 obbligatoria dopo:",
                        "options": [
                            "Il punto interrogativo",
                            "La virgola"
                        ],
                        "answer": "Il punto interrogativo"
                    },
                    {
                        "id": 306,
                        "title": "La Lettera H",
                        "theory": "La <span style=\"color: #27ae60; font-weight: bold;\">LETTERA H</span> in italiano \u00e8 muta, ma fondamentale.<br><br>Si usa principalmente per:<br>\u2022 Distinguere le forme del verbo <b>avere</b> (<i>ho, hai, ha, hanno</i>) da omofoni (<i>o, ai, a, anno</i>).<br>\u2022 Ottenere i suoni duri di <b>C</b> e <b>G</b> (es. <i>chilo, ghepardo</i>).<br>\u2022 All'interno di alcune esclamazioni (es. <i>ah, oh, ahi</i>).",
                        "text": "Quale frase usa correttamente la H?",
                        "options": [
                            "Ho comprato un libro.",
                            "Vado a casa o al mare."
                        ],
                        "answer": "Ho comprato un libro."
                    },
                    {
                        "id": 307,
                        "title": "Le Consonanti Doppie",
                        "theory": "Le <span style=\"color: #f39c12; font-weight: bold;\">CONSONANTI DOPPIE</span> rafforzano il suono della parola (es. <i>palla, gatto</i>).<br><br><b>Attenzione</b>:<br>\u2022 Non si raddoppia la <i>z</i> nelle parole che finiscono in <i>-zione</i> (es. <i>stazione</i>).<br>\u2022 Molte parole cambiano significato raddoppiando una lettera (es. <i>capello / cappello</i>, <i>casa / cassa</i>).",
                        "text": "La grafia corretta \u00e8:",
                        "options": [
                            "Azione",
                            "Azzione"
                        ],
                        "answer": "Azione"
                    }
                ],
